case class QueryValidationResult(isValid: Boolean, error: Option[String] = None)

class SQLQueryValidator(allowedTables: Set[String], allowedDatabases: Set[String] = Set("default")) {
  
  private val dangerousPatterns = List(
    Pattern.compile(".*;.*", Pattern.CASE_INSENSITIVE),
    Pattern.compile(".*--.*", Pattern.CASE_INSENSITIVE),
    Pattern.compile(".*/\\*.*\\*/.*", Pattern.CASE_INSENSITIVE),
    Pattern.compile(".*\\bEXEC\\b.*", Pattern.CASE_INSENSITIVE),
    Pattern.compile(".*\\bEXECUTE\\b.*", Pattern.CASE_INSENSITIVE),
    Pattern.compile(".*\\bxp_.*", Pattern.CASE_INSENSITIVE),
    Pattern.compile(".*\\bsp_.*", Pattern.CASE_INSENSITIVE)
  )
  
  private val allowedOperations = Set(
    classOf[Project],
    classOf[Filter],
    classOf[Aggregate],
    classOf[Sort],
    classOf[Join],
    classOf[Union],
    classOf[Limit],
    classOf[GlobalLimit],
    classOf[LocalLimit],
    classOf[SubqueryAlias],
    classOf[Distinct],
    classOf[Window]
  )
  
  def validate(query: String, spark: SparkSession): QueryValidationResult = {
    if (query == null || query.trim.isEmpty) {
      return QueryValidationResult(false, Some("Query cannot be empty"))
    }
    
    val normalizedQuery = query.trim
    
    if (normalizedQuery.length > 50000) {
      return QueryValidationResult(false, Some("Query exceeds maximum allowed length"))
    }
    
    for (pattern <- dangerousPatterns) {
      if (pattern.matcher(normalizedQuery).matches()) {
        return QueryValidationResult(false, Some("Query contains potentially dangerous patterns"))
      }
    }
    
    val queryUpper = normalizedQuery.toUpperCase
    val disallowedKeywords = List(
      "INSERT", "UPDATE", "DELETE", "DROP", "CREATE", "ALTER", 
      "TRUNCATE", "REPLACE", "MERGE", "GRANT", "REVOKE",
      "SET ", "RESET", "ADD JAR", "LIST JAR", "UNCACHE",
      "REFRESH", "LOAD DATA", "MSCK"
    )
    
    for (keyword <- disallowedKeywords) {
      if (queryUpper.contains(keyword)) {
        return QueryValidationResult(false, Some(s"Query contains disallowed operation: $keyword"))
      }
    }
    
    Try {
      val logicalPlan = spark.sessionState.sqlParser.parsePlan(normalizedQuery)
      validateLogicalPlan(logicalPlan)
    } match {
      case Success(result) => result
      case Failure(e: ParseException) => 
        QueryValidationResult(false, Some(s"Invalid SQL syntax: ${e.getMessage}"))
      case Failure(e) => 
        QueryValidationResult(false, Some(s"Query validation failed: ${e.getMessage}"))
    }
  }
  
  private def validateLogicalPlan(plan: LogicalPlan): QueryValidationResult = {
    val violations = scala.collection.mutable.ArrayBuffer[String]()
    
    plan.foreach {
      case cmd: Command =>
        violations += s"Command operations are not allowed: ${cmd.getClass.getSimpleName}"
        
      case relation: UnresolvedRelation =>
        val tableName = relation.tableName.toLowerCase
        val tableIdentifier = relation.multipartIdentifier.mkString(".")
        
        val dbName = if (relation.multipartIdentifier.length > 1) {
          relation.multipartIdentifier.head.toLowerCase
        } else {
          "default"
        }
        
        if (!allowedDatabases.contains(dbName)) {
          violations += s"Access to database '$dbName' is not allowed"
        }
        
        val actualTableName = if (relation.multipartIdentifier.length > 1) {
          relation.multipartIdentifier.last.toLowerCase
        } else {
          tableName
        }
        
        if (!allowedTables.contains(actualTableName) && !allowedTables.contains(tableIdentifier.toLowerCase)) {
          violations += s"Access to table '$tableIdentifier' is not allowed"
        }
        
      case node =>
        val nodeClass = node.getClass
        val isAllowed = allowedOperations.exists(_.isAssignableFrom(nodeClass)) ||
                       node.isInstanceOf[LeafNode] ||
                       node.nodeName == "UnresolvedRelation"
        
        if (!isAllowed && !nodeClass.getName.contains("Unresolved")) {
          violations += s"Operation not allowed: ${node.nodeName}"
        }
    }
    
    if (violations.nonEmpty) {
      QueryValidationResult(false, Some(violations.mkString("; ")))
    } else {
      QueryValidationResult(true)
    }
  }
}

class SecureQueryExecutor(spark: SparkSession, validator: SQLQueryValidator) {
  
  def executeQuery(userQuery: String, maxRows: Int = 10000): Try[DataFrame] = {
    Try {
      val validationResult = validator.validate(userQuery, spark)
      
      if (!validationResult.isValid) {
        throw new SecurityException(s"Query validation failed: ${validationResult.error.getOrElse("Unknown error")}")
      }
      
      val df = spark.sql(userQuery)
      df.limit(maxRows)
    }
  }
  
  def executeQueryWithTimeout(userQuery: String, timeoutSeconds: Int = 300, maxRows: Int = 10000): Try[DataFrame] = {
    Try {
      val validationResult = validator.validate(userQuery, spark)
      
      if (!validationResult.isValid) {
        throw new SecurityException(s"Query validation failed: ${validationResult.error.getOrElse("Unknown error")}")
      }
      
      spark.conf.set("spark.sql.broadcastTimeout", timeoutSeconds.toString)
      
      val df = spark.sql(userQuery)
      df.limit(maxRows)
    }
  }
}

