case class QueryRequest(query: String, maxRows: Option[Int] = None, timeoutSeconds: Option[Int] = None)
case class QueryResponse(success: Boolean, data: Option[String] = None, error: Option[String] = None, rowCount: Option[Long] = None)

class QueryAPIHandler(executor: SecureQueryExecutor) {
  
  def handleQueryRequest(request: QueryRequest): QueryResponse = {
    val maxRows = request.maxRows.getOrElse(10000)
    val timeout = request.timeoutSeconds.getOrElse(300)
    
    executor.executeQueryWithTimeout(request.query, timeout, maxRows) match {
      case Success(df) =>
        Try {
          val jsonData = df.toJSON.collect().mkString("[", ",", "]")
          val rowCount = df.count()
          QueryResponse(success = true, data = Some(jsonData), rowCount = Some(rowCount))
        } match {
          case Success(response) => response
          case Failure(e) => QueryResponse(success = false, error = Some(s"Failed to serialize results: ${e.getMessage}"))
        }
        
      case Failure(e: SecurityException) =>
        QueryResponse(success = false, error = Some(s"Security violation: ${e.getMessage}"))
        
      case Failure(e) =>
        QueryResponse(success = false, error = Some(s"Query execution failed: ${e.getMessage}"))
    }
  }
}